class Solution {
    public int makeTheIntegerZero(int num1, int num2) {
        if (num2 == 0) return num1 == 0 ? 0 : -1;
        int count = 0;
        while (num1 != 0) {
            if (num1 * num2 < 0) {
                return -1;
            }
            if (Math.abs(num2) > Math.abs(num1)) {
                return count + 1;
            }
            int i = 0;
            while ((2 * i + num2) <= num1) {
                i++;
            }
            i--;
            num1 -= (2 * i + num2);
            count++;
        }
        return count;
    }
}
